// ── LOADER MODULE ────────────────────────────────────────────────────
// Shown once per browser session, alternates randomly between Reduce and
// Eliminate loaders for campaign purposes.

import { safeHtml } from "./helpers.js";

export function initCampaignLoader() {
  // Already shown this session — remove overlay and exit
  if (sessionStorage.getItem('rea-loader-shown')) {
    document.getElementById('campaign-loader')?.remove();
    return;
  }

  const loaders = ['reduce', 'eliminate'];
  const pick    = loaders[Math.floor(Math.random() * loaders.length)];
  const mount   = document.getElementById('loader-mount');
  if (!mount) return;

  if (pick === 'reduce') {
    injectReduce(mount);
  } else {
    injectEliminate(mount);
  }
}

// ── DISMISS ───────────────────────────────────────────────────────────────────
function dismissLoader(delay) {
  setTimeout(() => {
    const el = document.getElementById('campaign-loader');
    if (!el) return;
    el.style.opacity = '0';
    setTimeout(() => {
      el.remove();
    }, 650);
    sessionStorage.setItem('rea-loader-shown', '1');
  }, delay);
}

// ── REDUCE ────────────────────────────────────────────────────────────────────
function injectReduce(mount) {
  mount.style.background = '#090814';
  mount.innerHTML = safeHtml(`
    <style>
      #rl-wrap {
        position: fixed; inset: 0; background: #090814;
        display: flex; flex-direction: column;
        align-items: center; justify-content: center;
        font-family: 'Century Gothic', sans-serif;
      }
      .rl-svg-wrap { position: relative; width: min(400px, 78vw); aspect-ratio: 745 / 800; }
      .rl-svg-layer { position: absolute; inset: 0; width: 100%; height: 100%; }
      .rl-svg-layer img { width: 100%; height: 100%; object-fit: cover; }
      #rl-pcanvas { position: absolute; inset: 0; pointer-events: none; }
      .rl-tagline {
        margin-top: 36px; font-size: 11px; font-weight: 400;
        letter-spacing: .28em; text-transform: uppercase;
        color: rgba(255,255,255,.22); height: 14px; transition: opacity .35s ease;
      }
      .rl-bar-track {
        width: min(340px, 72vw); height: 2px;
        background: rgba(255,255,255,.07); border-radius: 2px;
        overflow: hidden; margin-top: 18px;
      }
      .rl-bar-fill {
        height: 100%; width: 0%;
        background: linear-gradient(90deg, #3AB3E5, #6C63FF, #F8E200);
        border-radius: 2px;
      }
      .rl-blurb {
        margin-top: 28px; font-size: 13px; font-weight: 300;
        color: rgba(255,255,255,0); letter-spacing: .01em;
        text-align: center; line-height: 1.7; max-width: 300px;
        transition: color 1.2s ease;
      }
      .rl-blurb strong { font-weight: 600; color: rgba(248,226,0,0); transition: color 1.2s ease; }
      .rl-blurb.visible { color: rgba(255,255,255,.4); }
      .rl-blurb.visible strong { color: #F8E200; }
    </style>
    <div id="rl-wrap">
      <div class="rl-svg-wrap">
        <div class="rl-svg-layer" id="rl-before">
          <img src="data:image/svg+xml;base64," alt="" />
        </div>
        <div class="rl-svg-layer" id="rl-after" style="opacity:0">
          <img src="data:image/svg+xml;base64," alt="" />
        </div>
        <canvas id="rl-pcanvas"></canvas>
      </div>
      <p class="rl-tagline" id="rl-tag">reducing&nbsp;…</p>
      <div class="rl-bar-track"><div class="rl-bar-fill" id="rl-bar"></div></div>
      <p class="rl-blurb" id="rl-blurb">
        What if it took half the steps?<br>
        <strong>Reduce it — every idea is rewarded.</strong>
      </p>
    </div>`);

  runReduceAnim(dismissLoader);
}

function runReduceAnim(onComplete) {
  const DURATION = 4500;
  const barEl    = document.getElementById('rl-bar');
  const tagEl    = document.getElementById('rl-tag');
  const blurb    = document.getElementById('rl-blurb');
  const llBefore = document.getElementById('rl-before');
  const llAfter  = document.getElementById('rl-after');
  const canvas   = document.getElementById('rl-pcanvas');
  if (!canvas) return;

  const ctx     = canvas.getContext('2d');
  canvas.width  = canvas.offsetWidth  || 400;
  canvas.height = canvas.offsetHeight || 430;

  const MSGS       = ['reducing\u00a0…','simplifying\u00a0…','less steps\u00a0…','streamlined\u00a0…','done\u00a0…'];
  let mi           = 0;
  let blurbShown   = false;
  let burstFired   = false;
  let done         = false;
  const particles  = [];

  const msgInterval = setInterval(() => {
    mi = (mi + 1) % MSGS.length;
    tagEl.style.opacity = 0;
    setTimeout(() => { tagEl.textContent = MSGS[mi]; tagEl.style.opacity = 1; }, 260);
  }, 1000);

  function spawnBurst(n) {
    const cols = ['#3AB3E5', '#F8E200', '#fff', '#6C63FF'];
    for (let i = 0; i < n; i++) {
      const ang = Math.random() * Math.PI * 2;
      const spd = 2 + Math.random() * 8;
      particles.push({
        x: canvas.width / 2, y: canvas.height / 2,
        vx: Math.cos(ang) * spd, vy: Math.sin(ang) * spd,
        life: 1, decay: 0.014 + Math.random() * 0.02,
        r: 2 + Math.random() * 6,
        color: cols[Math.floor(Math.random() * cols.length)]
      });
    }
  }

  const t0 = performance.now();

  function frame(ts) {
    const raw = Math.min((ts - t0) / DURATION, 1);
    if (barEl) barEl.style.width = (raw * 100) + '%';

    const xprog = raw < 0.5 ? raw * 2 : (raw - 0.5) * 2;
    if (llBefore) llBefore.style.opacity = String(1 - xprog);
    if (llAfter)  llAfter.style.opacity  = String(xprog);

    if (raw > 0.49 && raw < 0.52 && !burstFired) { spawnBurst(100); burstFired = true; }
    if (raw > 0.70 && !blurbShown) { blurb?.classList.add('visible'); blurbShown = true; }

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    for (let i = particles.length - 1; i >= 0; i--) {
      const p = particles[i];
      p.x += p.vx; p.y += p.vy;
      p.vx *= 0.91; p.vy *= 0.91;
      p.life -= p.decay;
      if (p.life <= 0) { particles.splice(i, 1); continue; }
      ctx.save();
      ctx.globalAlpha = p.life * p.life;
      ctx.fillStyle   = p.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r * p.life, 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
    }

    if (raw < 1) {
      requestAnimationFrame(frame);
    } else {
      clearInterval(msgInterval);
      if (tagEl) tagEl.style.opacity = '0';
      if (!done) { done = true; onComplete(800); }
    }
  }

  requestAnimationFrame(frame);
}

// ── ELIMINATE ─────────────────────────────────────────────────────────────────
function injectEliminate(mount) {
  mount.style.background = '#39302D';
  mount.innerHTML = safeHtml(`
    <style>
      #el-root {
        font-family: 'Century Gothic', sans-serif; background: #39302D;
        width: 100%; height: 100%;
        display: flex; flex-direction: column;
        align-items: center; justify-content: center;
        padding: 36px 20px;
      }
      .el-track { width: 300px; height: 2px; background: rgba(255,255,255,.1); border-radius: 2px; overflow: hidden; margin-top: 28px; }
      .el-fill  { height: 100%; width: 0%; background: linear-gradient(90deg, #E4032C, #9F197E, #F8E200); border-radius: 2px; }
      #el-tag   { margin-top: 14px; font-size: 10px; font-weight: 700; letter-spacing: .26em; text-transform: uppercase; color: rgba(255,255,255,.28); min-height: 14px; transition: opacity .3s; }
      #el-blurb { margin-top: 22px; font-size: 13px; font-weight: 300; text-align: center; line-height: 1.75; max-width: 260px; opacity: 0; transition: opacity 1.6s ease; }
      #el-blurb strong { font-weight: 700; color: #F8E200; }
    </style>
    <div id="el-root">
      <canvas id="el-c" width="360" height="290"></canvas>
      <div class="el-track"><div class="el-fill" id="el-fill"></div></div>
      <p id="el-tag">eliminating&nbsp;…</p>
      <p id="el-blurb">
        What if it didn't need to exist?<br>
        <strong>Eliminate it — every idea is rewarded.</strong>
      </p>
    </div>`);

  runEliminateAnim(dismissLoader);
}

function runEliminateAnim(onComplete) {
  const TOTAL  = 8000;
  const canvas = document.getElementById('el-c');
  const ctx    = canvas?.getContext('2d');
  const fillEl = document.getElementById('el-fill');
  const tagEl  = document.getElementById('el-tag');
  const blurb  = document.getElementById('el-blurb');
  if (!canvas || !ctx) return;

  const W = 360, H = 290;

  const nodes = [
    { cx:72,  cy:72,  r:42, label:'Submit',  color:'#3AB3E5', op:1, sc:1 },
    { cx:196, cy:52,  r:34, label:'Review',  color:'#9F197E', op:1, sc:1 },
    { cx:305, cy:90,  r:36, label:'Approve', color:'#00A8A9', op:1, sc:1 },
    { cx:62,  cy:196, r:32, label:'Revise',  color:'#E4032C', op:1, sc:1 },
    { cx:196, cy:208, r:38, label:'Sign-off',color:'#F8E200', op:1, sc:1 },
    { cx:308, cy:214, r:30, label:'Archive', color:'#9F197E', op:1, sc:1 },
  ];
  const edges   = [[0,1],[1,2],[2,4],[0,3],[3,4],[1,4],[4,5],[2,5]];
  const edgeOp  = edges.map(() => 1);
  const targets = {
    edgeOp: edges.map(() => 1),
    nodeOp: nodes.map(() => 1),
    nodeSc: nodes.map(() => 1),
  };
  const fired     = new Set();
  const particles = [];
  const schedule  = [
    { type:'edge', idx:0, t:.20 }, { type:'edge', idx:2, t:.25 }, { type:'edge', idx:5, t:.29 },
    { type:'edge', idx:7, t:.33 }, { type:'edge', idx:1, t:.37 }, { type:'edge', idx:3, t:.41 },
    { type:'edge', idx:4, t:.45 }, { type:'edge', idx:6, t:.49 },
    { type:'node', idx:1, t:.55 }, { type:'node', idx:5, t:.61 },
    { type:'node', idx:2, t:.66 }, { type:'node', idx:3, t:.71 },
    { type:'node', idx:0, t:.77 }, { type:'node', idx:4, t:.83 },
  ];

  function burst(cx, cy, color, n) {
    const bc = [color, '#F8E200', '#fff', color];
    for (let i = 0; i < n; i++) {
      const spd = 2 + Math.random() * 7;
      const ang = Math.random() * Math.PI * 2;
      particles.push({
        x: cx, y: cy,
        vx: Math.cos(ang) * spd, vy: Math.sin(ang) * spd,
        life: 1, decay: .015 + Math.random() * .02,
        r: 2 + Math.random() * 7,
        color: bc[i % bc.length]
      });
    }
  }

  function triggerElimination(item) {
    if (item.type === 'edge') {
      targets.edgeOp[item.idx] = 0;
    } else {
      const n = nodes[item.idx];
      burst(n.cx, n.cy, n.color, 50);
      targets.nodeOp[item.idx] = 0;
      targets.nodeSc[item.idx] = 0.2;
    }
  }

  const MSGS = ['eliminating\u00a0…','removing the step\u00a0…','does this need to exist?\u00a0…','gone\u00a0…','what\u2019s next?\u00a0…'];
  let mi = 0;
  const mint = setInterval(() => {
    mi = (mi + 1) % MSGS.length;
    tagEl.style.opacity = 0;
    setTimeout(() => { tagEl.textContent = MSGS[mi]; tagEl.style.opacity = 1; }, 260);
  }, 1900);

  let blurbDone = false;
  let done      = false;
  const t0      = performance.now();

  function drawMotif() {
    ctx.save();
    ctx.globalAlpha  = .05;
    ctx.strokeStyle  = '#F8E200';
    ctx.lineWidth    = 1;
    [100, 150, 200].forEach(r => {
      ctx.beginPath(); ctx.arc(W / 2, H / 2, r, 0, Math.PI * 2); ctx.stroke();
    });
    ctx.beginPath(); ctx.moveTo(W/2, H/2-200); ctx.lineTo(W/2, H/2+200); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(W/2-200, H/2); ctx.lineTo(W/2+200, H/2); ctx.stroke();
    ctx.restore();
  }

  function frame(ts) {
    const raw = Math.min((ts - t0) / TOTAL, 1);
    if (fillEl) fillEl.style.width = (raw * 100) + '%';

    schedule.forEach(item => {
      const key = item.type + item.idx;
      if (raw >= item.t && !fired.has(key)) { fired.add(key); triggerElimination(item); }
    });

    const spd = 0.07;
    edgeOp.forEach((_, i) => { edgeOp[i] += (targets.edgeOp[i] - edgeOp[i]) * spd; });
    nodes.forEach((n, i) => {
      n.op += (targets.nodeOp[i] - n.op) * spd;
      n.sc += (targets.nodeSc[i] - n.sc) * spd;
    });

    for (let i = particles.length - 1; i >= 0; i--) {
      const p = particles[i];
      p.x += p.vx; p.y += p.vy;
      p.vx *= .91; p.vy *= .91;
      p.life -= p.decay;
      if (p.life <= 0) particles.splice(i, 1);
    }

    ctx.clearRect(0, 0, W, H);
    ctx.fillStyle = '#39302D';
    ctx.fillRect(0, 0, W, H);
    drawMotif();

    // edges
    edges.forEach(([a, b], i) => {
      if (edgeOp[i] <= 0) return;
      ctx.save();
      ctx.globalAlpha = edgeOp[i] * 0.25;
      ctx.strokeStyle = '#fff';
      ctx.lineWidth   = 1.5;
      ctx.setLineDash([5, 4]);
      ctx.beginPath();
      ctx.moveTo(nodes[a].cx, nodes[a].cy);
      ctx.lineTo(nodes[b].cx, nodes[b].cy);
      ctx.stroke();
      ctx.setLineDash([]);
      ctx.restore();
    });

    // nodes
    nodes.forEach(n => {
      if (n.op <= 0) return;
      ctx.save();
      ctx.globalAlpha = n.op;
      ctx.translate(n.cx, n.cy);
      ctx.scale(n.sc, n.sc);
      ctx.beginPath(); ctx.arc(0, 0, n.r + 9, 0, Math.PI * 2);
      ctx.strokeStyle  = n.color; ctx.lineWidth = 1;
      ctx.globalAlpha  = n.op * 0.3; ctx.stroke();
      ctx.globalAlpha  = n.op * 0.92;
      ctx.beginPath(); ctx.arc(0, 0, n.r, 0, Math.PI * 2);
      ctx.fillStyle = n.color; ctx.fill();
      ctx.globalAlpha    = n.op;
      ctx.fillStyle      = n.color === '#F8E200' ? '#39302D' : '#fff';
      ctx.font           = 'bold 11px Inter,sans-serif';
      ctx.textAlign      = 'center';
      ctx.textBaseline   = 'middle';
      ctx.fillText(n.label, 0, 0);
      ctx.restore();
    });

    // particles
    particles.forEach(p => {
      ctx.save();
      ctx.globalAlpha = p.life * p.life;
      ctx.fillStyle   = p.color;
      ctx.beginPath(); ctx.arc(p.x, p.y, p.r * p.life, 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
    });

    if (raw > .80 && !blurbDone) { blurbDone = true; if (blurb) blurb.style.opacity = 1; }

    if (raw < 1) {
      requestAnimationFrame(frame);
    } else {
      clearInterval(mint);
      if (tagEl) tagEl.style.opacity = '0';
      if (!done) { done = true; onComplete(800); }
    }
  }

  requestAnimationFrame(frame);
}